package com.example.mpos.customer;
import android.content.Intent;import android.os.Bundle;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.dao.CustomerDao;import com.example.mpos.database.DatabaseHelper;import com.example.mpos.model.Customer;import java.util.*;
public class CustomerListActivity extends AppCompatActivity{CustomerDao dao;ArrayAdapter<String> adapter;List<Customer> items=new ArrayList<>();EditText search;public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_customer_list);dao=new CustomerDao(new DatabaseHelper(this));search=findViewById(R.id.inputCustomerSearch);adapter=new ArrayAdapter<>(this,android.R.layout.simple_list_item_1,new ArrayList<>());ListView l=findViewById(R.id.listCustomers);l.setAdapter(adapter);findViewById(R.id.btnBack).setOnClickListener(v->finish());findViewById(R.id.btnSearchCustomer).setOnClickListener(v->load());findViewById(R.id.btnAddCustomer).setOnClickListener(v->startActivity(new Intent(this,CustomerFormActivity.class)));l.setOnItemClickListener((p,v,x,id)->{Intent i=new Intent(this,CustomerDetailActivity.class);i.putExtra("customer_id",items.get(x).id);startActivity(i);});load();}protected void onResume(){super.onResume();if(dao!=null)load();}void load(){items=dao.search(search.getText().toString());List<String> rows=new ArrayList<>();for(Customer c:items)rows.add((c.fullName==null?"Khách hàng":c.fullName)+"\n"+c.phone+" • "+c.loyaltyPoints+" điểm");adapter.clear();adapter.addAll(rows);adapter.notifyDataSetChanged();}}
